import (
	"container/heap"
)

type Edge struct {
	to    int64
	weight int64
}

type Item struct {
	node     int64
	cost     int64
	flipped  bool
	index    int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	graph := make(map[int64][]Edge)
	inEdges := make(map[int64][]Edge)
	for _, e := range edges {
		u, v, w := e[0], e[1], e[2]
		graph[u] = append(graph[u], Edge{v, w})
		inEdges[v] = append(inEdges[v], Edge{u, w})
	}

	dist := make([][]int64, n)
	for i := range dist {
		dist[i] = make([]int64, 2)
		dist[i][0] = 1 << 60
		dist[i][1] = 1 << 60
	}
	dist[0][0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{0, 0, false, 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u := item.node
		currentCost := item.cost
		flipped := item.flipped

		if u == n-1 {
			return currentCost
		}

		if currentCost > dist[u][boolToInt(flipped)] {
			continue
		}

		// Normal edges
		for _, e := range graph[u] {
			v := e.to
			w := e.weight
			if dist[v][boolToInt(flipped)] > currentCost + w {
				dist[v][boolToInt(flipped)] = currentCost + w
				heap.Push(&pq, &Item{v, dist[v][boolToInt(flipped)], flipped, len(pq)})
			}
		}

		// Flip an incoming edge if not flipped yet
		if !flipped {
			for _, e := range inEdges[u] {
				v := e.to
				w := e.weight
				newCost := currentCost + 2 * w
				if dist[v][1] > newCost {
					dist[v][1] = newCost
					heap.Push(&pq, &Item{v, newCost, true, len(pq)})
				}
			}
		}
	}

	minCost := min(dist[n-1][0], dist[n-1][1])
	if minCost == 1 << 60 {
		return -1
	}
	return minCost
}

func boolToInt(b bool) int64 {
	if b {
		return 1
	}
	return 0
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
