import (
	"container/heap"
)

type Edge struct {
	to   int64
	cost int64
}

type Item struct {
	node     int64
	cost     int64
	flipped  bool
	index    int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	graph := make(map[int64][]Edge)
	inEdges := make(map[int64][]Edge)
	for _, e := range edges {
		u, v, w := e[0], e[1], e[2]
		graph[u] = append(graph[u], Edge{v, w})
		inEdges[v] = append(inEdges[v], Edge{u, w})
	}

	dist := make([][]int64, n)
	for i := range dist {
		dist[i] = make([]int64, 2)
		dist[i][0] = 1 << 60
		dist[i][1] = 1 << 60
	}
	dist[0][0] = 0

