		// Flip an incoming edge if not flipped yet
		if !flipped {
			for _, e := range inEdges[u] {
				v := e.to
				w := e.cost
				newCost := currentCost + 2 * w
				if dist[v][1] > newCost {
					dist[v][1] = newCost
					heap.Push(&pq, &Item{v, newCost, true, 0})
				}
			}
		}
	}

	result := min(dist[n-1][0], dist[n-1][1])
	if result == 1 << 60 {
		return -1
	}
	return result
